#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const int partnerPos[8] = {3,4,5,0,1,2,7,6};
    const char *type[8] = {"LB","MB","UB","LB","MB","UB","SL","SU"};
    while (T--) {
        int N;
        scanf("%d", &N);
        int block = (N - 1) / 8;
        int pos = (N - 1) % 8;
        int pPos = partnerPos[pos];
        int partnerN = block * 8 + pPos + 1;
        printf("%d%s\n", partnerN, type[pPos]);
    }
    return 0;
}

